-- Validate a Redis key: must be a non-empty string, no null bytes, within length limit
-- Also prevents key patterns that could be used for attacks
local function validate_key(val)
    if type(val) ~= "string" then
        return false, "key must be a string"
    end
    if #val == 0 then
        return false, "key must not be empty"
    end
    if #val > MAX_KEY_LENGTH then
        return false, "key exceeds maximum length of " .. MAX_KEY_LENGTH
    end
    -- Reject null bytes
    if val:find("\0") then
        return false, "key must not contain null bytes"
    end
    return true
end

-- Validate a Redis value
local function validate_value(val)
    if type(val) ~= "string" then
        return false, "value must be a string"
    end
    if #val > MAX_VALUE_LENGTH then
        return false, "value exceeds maximum length of " .. MAX_VALUE_LENGTH
    end
    -- Reject null bytes
    if val:find("\0") then
        return false, "value must not contain null bytes"
    end
    return true
end

-- Validate a hash field name
local function validate_field(val)
    if type(val) ~= "string" then
        return false, "field must be a string"
    end
    if #val == 0 then
        return false, "field must not be empty"
    end
    if #val > MAX_KEY_LENGTH then
        return false, "field exceeds maximum length of " .. MAX_KEY_LENGTH
    end
    if val:find("\0") then
        return false, "field must not contain null bytes"
    end
    return true
end

-- Validate an integer string
local function validate_integer(val)
    if type(val) ~= "string" then
        return false, "integer argument must be a string"
    end
    if not val:match("^%-?%d+$") then
        return false, "argument must be a valid integer"
    end
    local num = tonumber(val)
    if not num then
        return false, "argument must be a valid integer"
    end
    -- Reasonable bounds
    if num > 2^53 or num < -(2^53) then
        return false, "integer out of safe range"
    end
    return true
end

-- Validate a positive integer
local function validate_positive_integer(val)
    local ok, err = validate_integer(val)
    if not ok then
        return false, err
    end
    if tonumber(val) <= 0 then
        return false, "argument must be a positive integer"
    end
    return true
end

-- Validate a non-negative integer
local function validate_non_negative_integer(val)
    local ok, err = validate_integer(val)
    if not ok then
        return false, err
    end
    if tonumber(val) < 0 then
        return false, "argument must be a non-negative integer"
    end
    return true
end

-- Validate a number (float or integer)
local function validate_number(val)
    if type(val) ~= "string" then
        return false, "number argument must be a string"
    end
    if not val:match("^%-?%d+%.?%d*$") and not val:match("^%-?%.%d+$") then
        return false, "argument must be a valid number"
    end
    local num = tonumber(val)
    if not num then
        return false, "argument must be a valid number"
    end
    return true
end

-- Validate a score boundary for ZCOUNT (can be -inf, +inf, (num, num)
local function validate_score_boundary(val)
    if type(val) ~= "string" then
        return false, "score boundary must be a string"
    end
    if val == "-inf" or val == "+inf" or val == "inf" then
        return true
    end
    -- Exclusive boundary like "(1.5"
    local inner = val:match("^%((.+)$")
    if inner then
        local num = tonumber(inner)
        if not num then
            return false, "invalid score boundary"
        end
        return true
    end
    -- Regular number
    local num = tonumber(val)
    if not num then
        return false, "invalid score boundary"
    end
    return true
end

-- Validate a SCAN pattern - restrict to safe glob patterns
local function validate_pattern(val)
    if type(val) ~= "string" then
        return false, "pattern must be a string"
    end
    if #val == 0 then
        return false, "pattern must not be empty"
    end
    if #val > MAX_KEY_LENGTH then
        return false, "pattern exceeds maximum length"
    end
    if val:find("\0") then
        return false, "pattern must not contain null bytes"
    end
    -- Only allow safe glob characters: *, ?, [, ], alphanumeric, common separators
    -- This prevents injection of Redis protocol characters
    if not val:match("^[%w%*%?%[%]%-_:%./ ]+$") then
        return false, "pattern contains disallowed characters"
    end
    return true
end

-- Validate SET command options
local function validate_set_option(val)
    if type(val) ~= "string" then
        return false, "SET option must be a string"
    end
    local upper = val:upper()
    if SET_OPTIONS[upper] then
        return true
    end
    -- Could also be the value for EX/PX/EXAT/PXAT (a number)
    if val:match("^%d+$") then
        return true
    end
    return false, "invalid SET option: " .. val
end

-- Validate SCAN options
local function validate_scan_option(val)
    if type(val) ~= "string" then
        return false, "SCAN option must be a string"
    end
    local upper = val:upper()
    if SCAN_OPTIONS[upper] then
        return true
    end
    return false, "invalid SCAN option: " .. val
end

-- Validate SCAN option values
local function validate_scan_option_value(val)
    if type(val) ~= "string" then
        return false, "SCAN option value must be a string"
    end
    -- Could be a MATCH pattern or COUNT number
    if val:match("^%d+$") then
        return true
    end
    -- Validate as pattern
    return validate_pattern(val)
end

-- Validate ZRANGE options
local function validate_zrange_option(val)
    if type(val) ~= "string" then
        return false, "ZRANGE option must be a string"
    end
    local upper = val:upper()
    if ZRANGE_OPTIONS[upper] then
        return true
    end
    return false, "invalid ZRANGE option: " .. val
end

-- Validate INFO section
local function validate_info_section(val)
    if type(val) ~= "string" then
        return false, "INFO section must be a string"
    end
    local lower = val:lower()
    if INFO_SECTIONS[lower] then
        return true
    end
    return false, "invalid INFO section: " .. val
end

