-- Validate variadic argument patterns
local function validate_variadic_args(arg_type_spec, args)
    if arg_type_spec == "keys" then
        -- All args are keys
        for i, arg in ipairs(args) do
            local ok, err = validate_key(arg)
            if not ok then
                return false, "argument " .. i .. ": " .. err
            end
        end
        return true

    elseif arg_type_spec == "list_values" or arg_type_spec == "set_values" then
        -- First arg is key, rest are values
        if #args < 2 then
            return false, "insufficient arguments"
        end
        local ok, err = validate_key(args[1])
        if not ok then
            return false, "argument 1 (key): " .. err
        end
        for i = 2, #args do
            ok, err = validate_value(args[i])
            if not ok then
                return false, "argument " .. i .. " (value): " .. err
            end
        end
        return true

    elseif arg_type_spec == "hash_fields" then
        -- First arg is key, rest are field names
        if #args < 2 then
            return false, "insufficient arguments"
        end
        local ok, err = validate_key(args[1])
        if not ok then
            return false, "argument 1 (key): " .. err
        end
        for i = 2, #args do
            ok, err = validate_field(args[i])
            if not ok then
                return false, "argument " .. i .. " (field): " .. err
            end
        end
        return true

    elseif arg_type_spec == "hash_field_values" then
        -- First arg is key, then alternating field/value pairs
        if #args < 3 then
            return false, "insufficient arguments"
        end
        local ok, err = validate_key(args[1])
        if not ok then
            return false, "argument 1 (key): " .. err
        end
        if (#args - 1) % 2 ~= 0 then
            return false, "hash field/value arguments must come in pairs"
        end
        for i = 2, #args, 2 do
            ok, err = validate_field(args[i])
            if not ok then
                return false, "argument " .. i .. " (field): " .. err
            end
            ok, err = validate_value(args[i + 1])
            if not ok then
                return false, "argument " .. (i + 1) .. " (value): " .. err
            end
        end
        return true

    elseif arg_type_spec == "zset_score_members" then
        -- First arg is key, then alternating score/member pairs
        if #args < 3 then
            return false, "insufficient arguments"
        end
        local ok, err = validate_key(args[1])
        if not ok then
            return false, "argument 1 (key): " .. err
        end
        if (#args - 1) % 2 ~= 0 then
            return false, "sorted set score/member arguments must come in pairs"
        end
        for i = 2, #args, 2 do
            ok, err = validate_number(args[i])
            if not ok then
                return false, "argument " .. i .. " (score): " .. err
            end
            ok, err = validate_value(args[i + 1])
            if not ok then
                return false, "argument " .. (i + 1) .. " (member): " .. err
            end
        end
        return true

    else
        return false, "unknown variadic argument type: " .. tostring(arg_type_spec)
    end
end

-- ============================================================================
-- COMMAND VALIDATION
-- ============================================================================

local function validate_command(command, args)
    -- Normalize command to uppercase
    if type(command) ~= "string" then
        return false, "command must be a string"
    end

    local cmd_upper = command:upper()

    -- Check if explicitly blocked
    if BLOCKED_COMMANDS[cmd_upper] then
        return false, "command '" .. cmd_upper .. "' is not allowed"
    end

    -- Check if in allowlist
    local spec = ALLOWED_COMMANDS[cmd_upper]
    if not spec then
        return false, "command '" .. cmd_upper .. "' is not in the allowlist"
    end

    -- Validate args is a table
    if type(args) ~= "table" then
        return false, "arguments must be an array"
    end

    -- Ensure all args are strings
    for i, arg in ipairs(args) do
        if type(arg) ~= "string" then
            return false, "argument " .. i .. " must be a string, got " .. type(arg)
        end
    end

    -- Check argument count
    local num_args = #args
    if num_args < spec.min_args then
        return false, "command '" .. cmd_upper .. "' requires at least " .. spec.min_args .. " argument(s), got " .. num_args
    end
    if num_args > spec.max_args then
        return false, "command '" .. cmd_upper .. "' accepts at most " .. spec.max_args .. " argument(s), got " .. num_args
    end

    -- Validate argument types
    if type(spec.arg_types) == "string" then
        -- Variadic argument pattern
        local ok, err = validate_variadic_args(spec.arg_types, args)
        if not ok then
            return false, "command '" .. cmd_upper .. "': " .. err
        end
    elseif type(spec.arg_types) == "table" then
        -- Fixed argument types
        for i, arg in ipairs(args) do
            local expected_type = spec.arg_types[i]
            if expected_type then
                local validator = TYPE_VALIDATORS[expected_type]
                if not validator then
                    return false, "internal error: unknown type validator '" .. expected_type .. "'"
                end
                local ok, err = validator(arg)
                if not ok then
                    return false, "command '" .. cmd_upper .. "' argument " .. i .. ": " .. err
                end
            end
        end
    end

    return true, cmd_upper
end

-- ============================================================================
-- REDIS CONNECTION MANAGEMENT
-- ============================================================================

local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "failed to connect to Redis: " .. tostring(err)
    end

    return red
end

local function release_redis_connection(red)
    if red then
        local ok, err = red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_KEEPALIVE_POOL_SIZE)
        if not ok then
            ngx.log(ngx.WARN, "failed to set Redis keepalive: ", err)
        end
    end
end

-- ============================================================================
-- EXECUTE REDIS COMMAND
-- ============================================================================

local function execute_redis_command(red, cmd, args)
    -- Use the Redis command method dynamically
    local cmd_lower = cmd:lower()
    local method = red[cmd_lower]

    if not method then
        return nil, "Redis client does not support command: " .. cmd
    end

    local result, err = method(red, unpack(args))
    if not result then
        return nil, "Redis command failed: " .. tostring(err)
    end

    return result
end

-- ============================================================================
-- REQUEST PARSING
-- ============================================================================

local function parse_request()
    local method = ngx.req.get_method()

    if method == "GET" then
        -- Parse from query parameters
        local args = ngx.req.get_uri_args()
        local command = args.cmd or args.command
        local cmd_args = {}

        -- Collect arguments: arg1, arg2, arg3, ...
        for i = 1, MAX_ARGS do
            local arg = args["arg" .. i]
            if arg then
                if type(arg) == "table" then
                    -- Multiple values for same parameter - reject
                    return nil, nil, "duplicate parameter arg" .. i .. " is not allowed"
                end
                cmd_args[#cmd_args + 1] = arg
            else
                break
            end
        end

        -- Also support 'args' as JSON array
        if #cmd_args == 0 and args.args then
            if type(args.args) == "table" then
                return nil, nil, "duplicate 'args' parameter is not allowed"
            end
            local decoded, decode_err = cjson.decode(args.args)
            if not decoded then
                return nil, nil, "failed to parse 'args' JSON: " .. tostring(decode_err)
            end
            if type(decoded) ~= "table" then
                return nil, nil, "'args' must be a JSON array"
            end
            -- Ensure it's an array (not an object)
            for k, _ in pairs(decoded) do
                if type(k) ~= "number" then
                    return nil, nil, "'args' must be a JSON array, not an object"
                end
            end
            -- Convert all values to strings
            for i, v in ipairs(decoded) do
                cmd_args[i] = tostring(v)
            end
        end

        if type(command) == "table" then
            return nil, nil, "duplicate 'cmd' parameter is not allowed"
        end

        return command, cmd_args, nil

    elseif method == "POST" then
        -- Parse from JSON body
        ngx.req.read_body()
        local body = ngx.req.get_body_data()

        if not body then
            return nil, nil, "request body is empty"
        end

        -- Limit body size
        if #body > 2 * 1024 * 1024 then  -- 2MB limit
            return nil, nil, "request body too large"
        end

        local data, decode_err = cjson.decode(body)
        if not data then
            return nil, nil, "failed to parse JSON body: " .. tostring(decode_err)
        end

        if type(data) ~= "table" then
            return nil, nil, "request body must be a JSON object"
        end

        local command = data.command or data.cmd
        local cmd_args = data.args or data.arguments or {}

        if type(cmd_args) ~= "table" then
            return nil, nil, "'args' must be an array"
        end

        -- Ensure args is an array, not an object
        for k, _ in pairs(cmd_args) do
            if type(k) ~= "number" then
                return nil, nil, "'args' must be a JSON array, not an object"
            end
        end

        -- Convert all argument values to strings
        local string_args = {}
        for i, v in ipairs(cmd_args) do
            if type(v) == "table" then
                return nil, nil, "argument " .. i .. " must not be an object or array"
            end
            string_args[i] = tostring(v)
        end

        return command, string_args, nil
    else
        return nil, nil, "only GET and POST methods are supported"
    end
end

-- ============================================================================
-- RESPONSE FORMATTING
-- ============================================================================

local function format_redis_result(result)
    if result == ngx.null then
        return cjson.null
    end

    if type(result) == "table" then
        local formatted = {}
        for i, v in ipairs(result) do
            if v == ngx.null then
                formatted[i] = cjson.null
            else
                formatted[i] = v
            end
        end
        return formatted
    end

    return result
end

local function send_json_response(status, data)
    ngx.status = status
    ngx.header["Content-Type"] = "application/json; charset=utf-8"
    ngx.header["X-Content-Type-Options"] = "nosniff"
    ngx.header["Cache-Control"] = "no-store, no-cache, must-revalidate"

    local json_str = cjson.encode(data)
    if not json_str then
        ngx.status = 500
        ngx.say('{"success":false,"error":"failed to encode response"}')
        return
    end

    ngx.say(json_str)
end

local function send_error(status, message)
    send_json_response(status, {
        success = false,
        error = message
    })
end

local function send_success(result, command, args)
    send_json_response(200, {
        success = true,
        command = command,
        args = args,
        result = format_redis_result(result)
    })
end

-- ============================================================================
-- RATE LIMITING (simple per-IP)
-- ============================================================================

local rate_limit_dict = ngx.shared.rate_limit

local function check_rate_limit()
    if not rate_limit_dict then
        -- Shared dict not configured; skip rate limiting but log warning
        ngx.log(ngx.WARN, "rate_limit shared dict not configured; skipping rate limiting")
        return true
    end

    local client_ip = ngx.var.remote_addr
    if not client_ip then
        return false, "unable to determine client IP"
    end

    local key = "rl:" .. client_ip
    local count, err = rate_limit_dict:incr(key, 1, 0, 60)  -- 60 second window

    if not count then
        ngx.log(ngx.ERR, "rate limit incr failed: ", err)
        return true  -- fail open on error
    end

    -- Allow 100 requests per minute per IP
    if count > 100 then
        return false, "rate limit exceeded, try again later"
    end

    return true
end

-- ============================================================================
-- AUDIT LOGGING
-- ============================================================================

local function audit_log(command, args, client_ip, success, error_msg)
    local log_entry = {
        timestamp = ngx.now(),
        client_ip = client_ip or ngx.var.remote_addr or "unknown",
        command = command,
        arg_count = args and #args or 0,
        success = success,
    }

    if error_msg then
        log_entry.error = error_msg
    end

    -- Log first key for context (but not values to avoid logging sensitive data)
    if args and #args > 0 then
        log_entry.first_key = args[1]
    end

    local log_str = cjson.encode(log_entry)
    if log_str then
        ngx.log(ngx.INFO, "REDIS_AUDIT: ", log_str)
    end
end

-- ============================================================================
-- HELP ENDPOINT
-- ============================================================================

local function handle_help()
    local commands = {}
    for cmd, spec in pairs(ALLOWED_COMMANDS) do
        commands[cmd] = {
            description = spec.description,
            min_args = spec.min_args,
            max_args = spec.max_args,
            readonly = spec.readonly,
        }
    end

    send_json_response(200, {
        success = true,
        message = "Redis Management Interface - Allowed Commands",
        usage = {
            GET_method = "GET /redis?cmd=GET&arg1=mykey",
            POST_method = 'POST /redis with JSON body: {"command":"GET","args":["mykey"]}',
            help = "GET /redis?cmd=help",
        },
        commands = commands
    })
end

-- ============================================================================
-- MAIN HANDLER
-- ============================================================================

local function main()
    -- Rate limiting
    local rate_ok, rate_err = check_rate_limit()
    if not rate_ok then
        send_error(429, rate_err)
        return
    end

    -- Parse request
    local command, args, parse_err = parse_request()
    if parse_err then
        audit_log(nil, nil, nil, false, parse_err)
        send_error(400, parse_err)
        return
    end

    if not command then
        audit_log(nil, nil, nil, false, "missing command")
        send_error(400, "missing 'cmd' or 'command' parameter")
        return
    end

    -- Handle help request
    if command:lower() == "help" then
        handle_help()
        return
    end

    -- Validate command and arguments
    local valid, cmd_or_err = validate_command(command, args)
    if not valid then
        audit_log(command, args, nil, false, cmd_or_err)
        send_error(400, cmd_or_err)
        return
    end

    local validated_cmd = cmd_or_err

    -- Connect to Redis
    local red, conn_err = get_redis_connection()
    if not red then
        audit_log(validated_cmd, args, nil, false, conn_err)
        send_error(502, conn_err)
        return
    end

    -- Execute command
    local result, exec_err = execute_redis_command(red, validated_cmd, args)

    -- Release connection back to pool
    release_redis_connection(red)

    if not result then
        audit_log(validated_cmd, args, nil, false, exec_err)
        send_error(500, exec_err)
        return
    end

    -- Success
    audit_log(validated_cmd, args, nil, true, nil)
    send_success(result, validated_cmd, args)
end

-- Execute main handler with error protection
local ok, err = pcall(main)
if not ok then
    ngx.log(ngx.ERR, "unhandled error in Redis handler: ", tostring(err))
    send_error(500, "internal server error")
end